INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('social-worker-moex-00871', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '有關社區的涵義，下列何者錯誤？', '["社區是希臘文夥伴（fellowship）的意思，指一群人集居在一起，共享互助，滿足基本需求，發 現生命意義", "Hillery將社區的定義加以整理，得出社區的要素包括人民、土地、社會互動及關係四者", "傳統社會裡社區很容易界定，通常指一群人住在一定的地理範圍內，與其他聚落有明顯的疆界 區隔", "地理社區經常交織著心理與社會的地盤，如地理上的區隔也會產生獨特的信仰、價值、行為與 目標"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00872', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '臺灣的社區發展歷史演進，自1983年至2005年，進入社區發展組織社團化的期間之敘述，下列 何者錯誤？', '["社區發展改為由下而上，鼓勵社區居民申請成立社區發展協會", "該時期政府函頒「社區發展工作綱要」，將原先偏重於政府主導的社區發展，改以人民團體型態 運作", "社區發展的主責單位為社區理事會", "該時期未針對社區差異需求，缺乏後續維護，效益大打折扣，埋下了後期社區總體營造興起的 種子"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00873', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於學者Rothman提出的地方發展模式，下列何者錯誤？', '["地方發展模式，也可以稱為自助模式", "地方發展模式期待產生人民生活實質條件、設備、服務的進步", "地方發展模式重視結果的重要性，目的是為了促進社區的發展", "地方發展模式的關鍵，在建立強而有力的社區感與合作的基礎"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00874', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '關於社區行動模式的敘述，下列何者錯誤？', '["社區衝突存在於社會中每一個角落，因價值、文化、利益、資源分配、信仰而有差異", "弱勢的一方受到強勢者的剝削而群起反抗，產生社區行動", "衝突經常無法被管理", "社區衝突可以是計畫性衝突，也可以是非計畫性衝突"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00875', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '立基於資產的社區發展模式工作原則，下列何者錯誤？', '["關注在社區欠缺與問題", "透過個人或組織的資產運用，建立關係", "關係是促進資產的連結與資產發揮的基礎", "在資產連結的組合刺激中，社區激發出想法與行動，朝著既定目標前進"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00876', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在社區工作的開案及初步評估階段，有關優先任務，下列何者錯誤？', '["進行社區資源評估及盤點", "訪談社區組織幹部及區公所人員", "瞭解居民對社區事務的參與態度", "執行具有成效導向的方案計畫"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00877', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '福利社區化的推展需要公私部門的資源投入，關於資源特性，下列何者錯誤？', '["政府資源具有公信力但缺乏彈性", "非營利部門資源與組織使命相連結", "非營利組織財力通常穩定且自主", "非正式部門立基於鄰里互助及家庭倫理"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-00878', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '在規劃社區福利服務的過程中，關於社區資源運用的核心原則，下列何者錯誤？', '["使用的資源類別越多越有保障", "避免過度依賴單一資源或服務", "符合社區實際的需要", "運用資源的過程能接受查核"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
