  ('social-worker-moex-00880', 'social-worker', 'social-worker-moex-111-694fe135', 'sub-social-worker-03', NULL, 'single_choice', '對「社區關懷照顧據點」的實施情形，下列敘述何者錯誤？', '["多半仰賴社區志工來提供服務", "實踐長者在地安老的宗旨", "提供健康促進及關懷訪視服務", "依法限定社區發展協會為執行單位"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:05+00:00", "source_pdf_sha1": "9046531e4762", "answer_pdf_sha1": "3da94ece26cf", "source_family": "moex-gov-tw", "moex": {"exam_code": "111030", "c": "105", "s": "0402", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作直接服務", "year": "111", "exam_name": "111年第一次專技人員高等考試中醫師考試分階段考試、營養師、護理師、社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
